import pandas as pd
from dataclasses import dataclass
from typing import Optional

@dataclass
class DataSourceProfile:
    source_name: str
    total_records: int
    key_fields: list[str]

    def assess_completeness(self, df: pd.DataFrame) -> dict:
        """Compute completeness for each key field."""
        results = {}
        for field in self.key_fields:
            if field not in df.columns:
                results[field] = {"pct_complete": 0.0, "status": "BLOCKING", "note": "field missing"}
                continue
            pct = df[field].notna().mean()
            if pct >= 0.90:
                status = "READY"
            elif pct >= 0.75:
                status = "CONDITIONAL"
            else:
                status = "BLOCKING"
            results[field] = {"pct_complete": round(pct, 3), "status": status}
        return results

    def assess_freshness(self, timestamp_field: str, df: pd.DataFrame,
                          max_lag_hours: float) -> dict:
        """Check whether data is sufficiently recent."""
        import datetime
        latest = pd.to_datetime(df[timestamp_field]).max()
        lag_hours = (datetime.datetime.utcnow() - latest.to_pydatetime().replace(tzinfo=None)).total_seconds() / 3600
        if lag_hours <= max_lag_hours:
            status = "READY"
        elif lag_hours <= max_lag_hours * 3:
            status = "CONDITIONAL"
        else:
            status = "BLOCKING"
        return {"lag_hours": round(lag_hours, 1), "threshold_hours": max_lag_hours, "status": status}


# Usage
df = pd.read_parquet("s3://data-lake/customer-profiles/latest.parquet")
profile = DataSourceProfile(
    source_name="customer-profiles",
    total_records=len(df),
    key_fields=["account_status", "product_tier", "contract_end_date", "email"],
)
completeness = profile.assess_completeness(df)
freshness = profile.assess_freshness("updated_at", df, max_lag_hours=6.0)
print("Completeness:", completeness)
print("Freshness:", freshness)

from dataclasses import dataclass, field
from typing import Literal

ReadinessStatus = Literal["READY", "CONDITIONAL", "BLOCKING"]

@dataclass
class AssessmentFinding:
    dimension: str
    status: ReadinessStatus
    detail: str
    remediation: str = ""
    owner: str = ""
    due_date: str = ""

@dataclass
class DataReadinessReport:
    source_name: str
    findings: list[AssessmentFinding] = field(default_factory=list)

    def overall_status(self) -> ReadinessStatus:
        statuses = {f.status for f in self.findings}
        if "BLOCKING" in statuses:
            return "BLOCKING"
        if "CONDITIONAL" in statuses:
            return "CONDITIONAL"
        return "READY"

    def blocking_count(self) -> int:
        return sum(1 for f in self.findings if f.status == "BLOCKING")

    def summary(self) -> str:
        lines = [f"Data Source: {self.source_name}",
                 f"Overall: {self.overall_status()}",
                 f"Blocking findings: {self.blocking_count()}"]
        for f in self.findings:
            lines.append(f"  [{f.status}] {f.dimension}: {f.detail}")
            if f.remediation:
                lines.append(f"    Remediation: {f.remediation} (Owner: {f.owner}, Due: {f.due_date})")
        return "\n".join(lines)


report = DataReadinessReport(source_name="customer-profiles")
report.findings = [
    AssessmentFinding("Completeness", "READY", "96% on all key fields"),
    AssessmentFinding("Freshness", "CONDITIONAL", "6h lag; threshold 1h",
        remediation="Add streaming CDC pipeline", owner="Data Eng", due_date="2025-03-15"),
    AssessmentFinding("Schema Stability", "READY", "No breaking changes in 18 months"),
    AssessmentFinding("Access Permissions", "BLOCKING", "Service account IAM request pending",
        remediation="Submit IAM ticket #4821; DLP review required", owner="Security", due_date="2025-02-28"),
    AssessmentFinding("Grounding Quality", "CONDITIONAL", "74% precision at k=5",
        remediation="Improve chunking; add metadata filters", owner="ML Eng", due_date="2025-03-01"),
    AssessmentFinding("Lineage", "READY", "Full field-level lineage documented in DataHub"),
]
print(report.summary())
